CustomField.formula:
IF(Overdue_Days_Formula__c < -180, "< -180",
			IF(Overdue_Days_Formula__c < -90, "-(91-180)",
						IF(Overdue_Days_Formula__c < -60, "-(61-90)",
									IF(Overdue_Days_Formula__c < -30, "-(31-60)",
												IF(Overdue_Days_Formula__c <= 0, "-(0-30)",
             IF(Overdue_Days_Formula__c <= 30, "1-30",
                IF(Overdue_Days_Formula__c <= 60, "31-60",
                  IF(Overdue_Days_Formula__c <= 90, "61-90",
                    IF(Overdue_Days_Formula__c <= 180, "91-180","Over 180"
)
)
)
)
)
									)
						)
			)
			)
